import asyncio
from pyppeteer import launch

async def take_screenshot(url):
    browser = await launch()
    page = await browser.newPage()
    await page.goto(url)
    await page.screenshot({'path': 'example.png'})  # Save screenshot as example.png in current directory
    await browser.close()